import './StickyNode.scss';

import type { LexicalEditor, NodeKey } from 'lexical';
import type { JSX } from 'react';
import {
  useCallback,
  useEffect,
  useLayoutEffect,
  useRef,
  useState,
} from 'react';

import { useCollaborationContext } from '@lexical/react/LexicalCollaborationContext';
import { CollaborationPlugin } from '@lexical/react/LexicalCollaborationPlugin';
import { useLexicalComposerContext } from '@lexical/react/LexicalComposerContext';
import { LexicalErrorBoundary } from '@lexical/react/LexicalErrorBoundary';
import { HistoryPlugin } from '@lexical/react/LexicalHistoryPlugin';
import { LexicalNestedComposer } from '@lexical/react/LexicalNestedComposer';
import { PlainTextPlugin } from '@lexical/react/LexicalPlainTextPlugin';
import { useLexicalEditable } from '@lexical/react/useLexicalEditable';
import { calculateZoomLevel } from '@lexical/utils';
import {
  $addUpdateTag,
  $getNodeByKey,
  $setSelection,
  SKIP_SELECTION_FOCUS_TAG,
} from 'lexical';

import { createWebsocketProvider } from '../collaboration';
import { useSharedHistoryContext } from '../context/SharedHistoryContext';
import { useStickyNoteFontFamilies } from '../context/StickyNotesContext';
import StickyEditorTheme from '../themes/StickyEditorTheme';
import ContentEditable from '../ui/ContentEditable';
import {
  $isStickyNode,
  DEFAULT_STICKY_NOTE_LAYER,
  MIN_STICKY_NOTE_HEIGHT,
  MIN_STICKY_NOTE_WIDTH,
  STICKY_NOTE_LAYER_BASE,
  type StickyNoteColor,
} from './StickyNode';

const STICKY_POINTER_THRESHOLD_PX = 4;
const STICKY_RESIZE_CLICK_SCALE_STEP = 0.12;

function clamp(value: number, min: number, max: number): number {
  return Math.min(Math.max(value, min), max);
}

type Positioning = {
  hasMoved: boolean;
  isDragging: boolean;
  offsetX: number;
  offsetY: number;
  pointerId: null | number;
  positioningFrameRect: null | ClientRect;
  startX: number;
  startY: number;
  x: number;
  y: number;
};

type Resizing = {
  hasMoved: boolean;
  height: number;
  isResizing: boolean;
  pointerId: null | number;
  startClientX: number;
  startClientY: number;
  startHeight: number;
  startWidth: number;
  width: number;
};

function positionSticky(
  stickyElem: HTMLElement,
  positioning: Positioning,
): void {
  const style = stickyElem.style;
  const clampedPosition = clampStickyPosition(
    stickyElem,
    positioning,
    positioning.x,
    positioning.y,
  );

  positioning.x = clampedPosition.x;
  positioning.y = clampedPosition.y;
  style.top = positioning.y + 'px';
  style.left = positioning.x + 'px';
}

function clampStickyPosition(
  stickyElem: HTMLElement,
  positioning: Positioning,
  x: number,
  y: number,
): { x: number; y: number } {
  const positioningFrameRect = positioning.positioningFrameRect;

  if (positioningFrameRect === null) {
    return { x, y };
  }

  const zoom = calculateZoomLevel(stickyElem);
  const stickyRect = stickyElem.getBoundingClientRect();
  const rootWidth = positioningFrameRect.width / zoom;
  const rootHeight = positioningFrameRect.height / zoom;
  const stickyWidth = stickyRect.width / zoom;
  const stickyHeight = stickyRect.height / zoom;

  return {
    x: clamp(x, 0, Math.max(0, rootWidth - stickyWidth)),
    y: clamp(y, 0, Math.max(0, rootHeight - stickyHeight)),
  };
}

function clampStickySize(
  stickyContainer: HTMLElement,
  stickyNote: HTMLElement,
  positioning: Positioning,
  width: number,
  height: number,
): { height: number; width: number } {
  const positioningFrameRect = positioning.positioningFrameRect;

  if (positioningFrameRect === null) {
    return {
      height: Math.round(Math.max(MIN_STICKY_NOTE_HEIGHT, height)),
      width: Math.round(Math.max(MIN_STICKY_NOTE_WIDTH, width)),
    };
  }

  const zoom = calculateZoomLevel(stickyNote);
  const stickyContainerRect = stickyContainer.getBoundingClientRect();
  const stickyNoteRect = stickyNote.getBoundingClientRect();
  const rootWidth = positioningFrameRect.width / zoom;
  const rootHeight = positioningFrameRect.height / zoom;
  const chromeWidth = Math.max(
    0,
    (stickyContainerRect.width - stickyNoteRect.width) / zoom,
  );
  const chromeHeight = Math.max(
    0,
    (stickyContainerRect.height - stickyNoteRect.height) / zoom,
  );
  const maxWidth = Math.max(
    MIN_STICKY_NOTE_WIDTH,
    rootWidth - positioning.x - chromeWidth,
  );
  const maxHeight = Math.max(
    MIN_STICKY_NOTE_HEIGHT,
    rootHeight - positioning.y - chromeHeight,
  );

  return {
    height: Math.round(clamp(height, MIN_STICKY_NOTE_HEIGHT, maxHeight)),
    width: Math.round(clamp(width, MIN_STICKY_NOTE_WIDTH, maxWidth)),
  };
}

function getStickyPositioningFrame(editor: LexicalEditor): HTMLElement | null {
  const rootElement = editor.getRootElement();

  if (rootElement === null) {
    return null;
  }

  return rootElement.closest<HTMLElement>('.editor-scroller') ?? rootElement;
}

function getStickyContainerZIndex(stickyContainer: HTMLElement): number {
  const styleZIndex = Number.parseInt(stickyContainer.style.zIndex, 10);

  if (Number.isFinite(styleZIndex)) {
    return styleZIndex;
  }

  const computedZIndex = Number.parseInt(
    window.getComputedStyle(stickyContainer).zIndex,
    10,
  );

  return Number.isFinite(computedZIndex)
    ? computedZIndex
    : STICKY_NOTE_LAYER_BASE;
}

function getNextTransientStickyZIndex(stickyContainer: HTMLElement): number {
  const stickyRoot = stickyContainer.parentElement ?? document.body;
  const stickyContainers = Array.from(
    stickyRoot.querySelectorAll<HTMLElement>('.sticky-note-container'),
  );
  const highestZIndex = stickyContainers.reduce(
    (highest, currentContainer) =>
      Math.max(highest, getStickyContainerZIndex(currentContainer)),
    STICKY_NOTE_LAYER_BASE,
  );

  return highestZIndex + 1;
}

export default function StickyComponent({
  x,
  y,
  nodeKey,
  color,
  caption,
  width,
  height,
  extraFontFamilies,
  layer = DEFAULT_STICKY_NOTE_LAYER,
}: {
  caption: LexicalEditor;
  color: StickyNoteColor;
  extraFontFamilies?: ReadonlyArray<string>;
  height: number;
  layer?: number;
  nodeKey: NodeKey;
  width: number;
  x: number;
  y: number;
}): JSX.Element {
  const [editor] = useLexicalComposerContext();
  const isEditable = useLexicalEditable();
  const configuredExtraFontFamilies = useStickyNoteFontFamilies();
  const resolvedExtraFontFamilies =
    extraFontFamilies ?? configuredExtraFontFamilies;
  const [transientZIndex, setTransientZIndex] = useState<number | null>(null);
  const stickyContainerRef = useRef<null | HTMLDivElement>(null);
  const stickyNoteRef = useRef<null | HTMLDivElement>(null);
  const positioningRef = useRef<Positioning>({
    hasMoved: false,
    isDragging: false,
    offsetX: 0,
    offsetY: 0,
    pointerId: null,
    positioningFrameRect: null,
    startX: 0,
    startY: 0,
    x: 0,
    y: 0,
  });
  const resizingRef = useRef<Resizing>({
    hasMoved: false,
    height,
    isResizing: false,
    pointerId: null,
    startClientX: 0,
    startClientY: 0,
    startHeight: height,
    startWidth: width,
    width,
  });
  const { isCollabActive } = useCollaborationContext();

  const focusStickyNote = useCallback(() => {
    if (!isEditable) {
      const stickyContainer = stickyContainerRef.current;

      if (stickyContainer !== null) {
        setTransientZIndex(getNextTransientStickyZIndex(stickyContainer));
      }
      return;
    }

    editor.update(() => {
      $addUpdateTag(SKIP_SELECTION_FOCUS_TAG);
      $setSelection(null);
      const node = $getNodeByKey(nodeKey);
      if ($isStickyNode(node)) {
        node.bringToFront();
      }
    });
  }, [editor, isEditable, nodeKey]);

  useEffect(() => {
    if (isEditable) {
      setTransientZIndex(null);
    }
  }, [isEditable, layer]);

  useEffect(() => {
    if (isCollabActive) {
      return;
    }

    return caption.registerUpdateListener(() => {
      editor.update(() => {
        const node = $getNodeByKey(nodeKey);
        if ($isStickyNode(node)) {
          node.markCaptionChanged();
        }
      });
    });
  }, [caption, editor, isCollabActive, nodeKey]);

  useLayoutEffect(() => {
    const position = positioningRef.current;
    position.x = x;
    position.y = y;

    const stickyContainer = stickyContainerRef.current;
    if (stickyContainer !== null) {
      positionSticky(stickyContainer, position);
    }
  }, [x, y]);

  useEffect(() => {
    const resizing = resizingRef.current;
    resizing.width = width;
    resizing.height = height;
  }, [width, height]);

  const refreshPositioningFrameRect = useCallback(() => {
    const positioningFrame = getStickyPositioningFrame(editor);
    const positioning = positioningRef.current;

    if (positioningFrame !== null) {
      positioning.positioningFrameRect =
        positioningFrame.getBoundingClientRect();
    }

    return positioning.positioningFrameRect;
  }, [editor]);

  const persistStickySize = (nextWidth: number, nextHeight: number) => {
    editor.update(() => {
      const node = $getNodeByKey(nodeKey);
      if ($isStickyNode(node)) {
        node.setSize(nextWidth, nextHeight);
      }
    });
  };

  const applyStickySize = (nextWidth: number, nextHeight: number) => {
    const stickyContainer = stickyContainerRef.current;
    const stickyNote = stickyNoteRef.current;
    const positioning = positioningRef.current;

    if (stickyContainer === null || stickyNote === null) {
      return null;
    }

    const clampedSize = clampStickySize(
      stickyContainer,
      stickyNote,
      positioning,
      nextWidth,
      nextHeight,
    );
    const resizing = resizingRef.current;

    stickyNote.style.width = `${clampedSize.width}px`;
    stickyNote.style.height = `${clampedSize.height}px`;
    resizing.width = clampedSize.width;
    resizing.height = clampedSize.height;
    positionSticky(stickyContainer, positioning);

    return clampedSize;
  };

  useLayoutEffect(() => {
    const position = positioningRef.current;
    let observedPositioningFrame: HTMLElement | null = null;
    const resizeObserver = new ResizeObserver((entries) => {
      for (let i = 0; i < entries.length; i++) {
        const entry = entries[i];
        const { target } = entry;
        position.positioningFrameRect = target.getBoundingClientRect();
        const stickyContainer = stickyContainerRef.current;
        if (stickyContainer !== null) {
          positionSticky(stickyContainer, position);
        }
      }
    });

    const observePositioningFrame = () => {
      if (observedPositioningFrame !== null) {
        resizeObserver.unobserve(observedPositioningFrame);
      }

      const positioningFrame = getStickyPositioningFrame(editor);
      observedPositioningFrame = positioningFrame;

      if (positioningFrame !== null) {
        position.positioningFrameRect =
          positioningFrame.getBoundingClientRect();
        resizeObserver.observe(positioningFrame);
      } else {
        position.positioningFrameRect = null;
      }

      const stickyContainer = stickyContainerRef.current;
      if (stickyContainer !== null) {
        positionSticky(stickyContainer, position);
      }
    };

    const removeRootListener = editor.registerRootListener((nextRootElem) => {
      if (nextRootElem !== null) {
        observePositioningFrame();
        return;
      }

      if (observedPositioningFrame !== null) {
        resizeObserver.unobserve(observedPositioningFrame);
        observedPositioningFrame = null;
      }
    });

    const handleWindowResize = () => {
      const rootElement = editor.getRootElement();
      const stickyContainer = stickyContainerRef.current;
      if (rootElement !== null && stickyContainer !== null) {
        refreshPositioningFrameRect();
        positionSticky(stickyContainer, position);
      }
    };

    window.addEventListener('resize', handleWindowResize);

    return () => {
      window.removeEventListener('resize', handleWindowResize);
      removeRootListener();
    };
  }, [editor, refreshPositioningFrameRect]);

  useEffect(() => {
    const stickyContainer = stickyContainerRef.current;
    if (stickyContainer !== null) {
      // Delay adding transition so we don't trigger the
      // transition on load of the sticky.
      setTimeout(() => {
        stickyContainer.style.setProperty(
          'transition',
          'top 0.3s ease 0s, left 0.3s ease 0s',
        );
      }, 500);
    }
  }, []);

  const handlePointerMove = (event: PointerEvent) => {
    const stickyContainer = stickyContainerRef.current;
    const positioning = positioningRef.current;
    const positioningFrameRect = positioning.positioningFrameRect;
    const zoom = calculateZoomLevel(stickyContainer);

    if (positioning.pointerId !== event.pointerId) {
      return;
    }

    if (
      stickyContainer !== null &&
      positioning.isDragging &&
      positioningFrameRect !== null
    ) {
      const deltaX = event.clientX - positioning.startX;
      const deltaY = event.clientY - positioning.startY;

      if (!positioning.hasMoved) {
        const distance = Math.abs(deltaX) + Math.abs(deltaY);

        if (distance < STICKY_POINTER_THRESHOLD_PX) {
          return;
        }

        positioning.hasMoved = true;
        stickyContainer.classList.add('dragging');
      }

      positioning.x =
        event.clientX / zoom - positioning.offsetX - positioningFrameRect.left;
      positioning.y =
        event.clientY / zoom - positioning.offsetY - positioningFrameRect.top;
      positionSticky(stickyContainer, positioning);
      event.preventDefault();
    }
  };

  const handlePointerUp = (event: PointerEvent) => {
    const stickyContainer = stickyContainerRef.current;
    const positioning = positioningRef.current;

    if (positioning.pointerId !== event.pointerId) {
      return;
    }

    if (stickyContainer !== null) {
      positioning.isDragging = false;
      positioning.pointerId = null;
      positioning.hasMoved = false;
      stickyContainer.classList.remove('dragging');
      editor.update(() => {
        const node = $getNodeByKey(nodeKey);
        if ($isStickyNode(node)) {
          node.setPosition(positioning.x, positioning.y);
        }
      });
    }
    event.preventDefault();
    document.removeEventListener('pointermove', handlePointerMove);
    document.removeEventListener('pointerup', handlePointerUp);
    document.removeEventListener('pointercancel', handlePointerUp);
  };

  const handleResizePointerMove = (event: PointerEvent) => {
    const stickyContainer = stickyContainerRef.current;
    const stickyNote = stickyNoteRef.current;
    const resizing = resizingRef.current;
    const zoom = calculateZoomLevel(stickyNote);

    if (resizing.pointerId !== event.pointerId) {
      return;
    }

    if (
      stickyContainer !== null &&
      stickyNote !== null &&
      resizing.isResizing
    ) {
      const deltaX = event.clientX - resizing.startClientX;
      const deltaY = event.clientY - resizing.startClientY;

      if (!resizing.hasMoved) {
        const distance = Math.abs(deltaX) + Math.abs(deltaY);

        if (distance < STICKY_POINTER_THRESHOLD_PX) {
          return;
        }

        resizing.hasMoved = true;
        stickyNote.classList.add('resizing');
      }

      applyStickySize(
        resizing.startWidth + deltaX / zoom,
        resizing.startHeight + deltaY / zoom,
      );
      event.preventDefault();
    }
  };

  const increaseStickySizeByStep = () => {
    const resizing = resizingRef.current;
    const nextSize = applyStickySize(
      resizing.width * (1 + STICKY_RESIZE_CLICK_SCALE_STEP),
      resizing.height * (1 + STICKY_RESIZE_CLICK_SCALE_STEP),
    );

    if (nextSize !== null) {
      persistStickySize(nextSize.width, nextSize.height);
    }
  };

  const handleResizePointerUp = (event: PointerEvent) => {
    const stickyNote = stickyNoteRef.current;
    const resizing = resizingRef.current;

    if (resizing.pointerId !== event.pointerId) {
      return;
    }

    const resizedByDrag = resizing.hasMoved;

    if (stickyNote !== null) {
      resizing.isResizing = false;
      resizing.pointerId = null;
      resizing.hasMoved = false;
      stickyNote.classList.remove('resizing');
    }
    event.preventDefault();
    document.removeEventListener('pointermove', handleResizePointerMove);
    document.removeEventListener('pointerup', handleResizePointerUp);
    document.removeEventListener('pointercancel', handleResizePointerUp);

    if (!resizedByDrag) {
      increaseStickySizeByStep();
      return;
    }

    persistStickySize(resizing.width, resizing.height);
  };

  const handleDelete = () => {
    editor.update(() => {
      const node = $getNodeByKey(nodeKey);
      if ($isStickyNode(node)) {
        node.remove();
      }
    });
  };

  const handleColorChange = () => {
    editor.update(() => {
      const node = $getNodeByKey(nodeKey);
      if ($isStickyNode(node)) {
        node.toggleColor();
      }
    });
  };

  const { historyState } = useSharedHistoryContext();

  return (
    <div
      ref={stickyContainerRef}
      className="sticky-note-container"
      style={{ zIndex: transientZIndex ?? STICKY_NOTE_LAYER_BASE + layer }}
    >
      <div
        ref={stickyNoteRef}
        className={`sticky-note ${color}`}
        style={{
          height,
          width,
          fontFamily: [
            '"Indie Flower"',
            ...resolvedExtraFontFamilies,
            'cursive',
          ].join(', '),
        }}
        onFocus={focusStickyNote}
        onPointerDownCapture={focusStickyNote}
        onPointerDown={(event) => {
          const stickyContainer = stickyContainerRef.current;
          if (
            stickyContainer == null ||
            event.button === 2 ||
            event.target !== stickyContainer.firstChild
          ) {
            // Right click or click on editor should not work
            return;
          }
          const stickContainer = stickyContainer;
          const positioning = positioningRef.current;
          if (stickContainer !== null) {
            refreshPositioningFrameRect();
            const { top, left } = stickContainer.getBoundingClientRect();
            const zoom = calculateZoomLevel(stickContainer);
            positioning.offsetX = event.clientX / zoom - left;
            positioning.offsetY = event.clientY / zoom - top;
            positioning.pointerId = event.pointerId;
            positioning.startX = event.clientX;
            positioning.startY = event.clientY;
            positioning.hasMoved = false;
            positioning.isDragging = true;
            document.addEventListener('pointermove', handlePointerMove);
            document.addEventListener('pointerup', handlePointerUp);
            document.addEventListener('pointercancel', handlePointerUp);
            event.preventDefault();
          }
        }}
      >
        <div className="top-right-buttons">
          <button
            onClick={handleColorChange}
            aria-label="Change sticky note color"
            title="Color"
          >
            <i className="bi bi-paint-bucket" />
          </button>
          <button
            onClick={handleDelete}
            aria-label="Delete sticky note"
            title="Delete"
          >
            <i className="bi bi-x-lg" style={{ color: 'red' }} />
          </button>
        </div>
        <button
          className="resize"
          aria-label="Resize sticky note"
          title="Resize"
          onPointerDown={(event) => {
            const stickyNote = stickyNoteRef.current;
            if (stickyNote === null || event.button === 2) {
              return;
            }
            refreshPositioningFrameRect();
            const resizing = resizingRef.current;
            resizing.isResizing = true;
            resizing.pointerId = event.pointerId;
            resizing.hasMoved = false;
            resizing.startClientX = event.clientX;
            resizing.startClientY = event.clientY;
            resizing.startWidth = resizing.width;
            resizing.startHeight = resizing.height;
            document.addEventListener('pointermove', handleResizePointerMove);
            document.addEventListener('pointerup', handleResizePointerUp);
            document.addEventListener('pointercancel', handleResizePointerUp);
            event.preventDefault();
            event.stopPropagation();
          }}
        >
          <i className="bi bi-arrow-down-right" />
        </button>
        <LexicalNestedComposer
          initialEditor={caption}
          initialTheme={StickyEditorTheme}
        >
          {isCollabActive ? (
            <CollaborationPlugin
              id={caption.getKey()}
              providerFactory={createWebsocketProvider}
              shouldBootstrap={true}
            />
          ) : (
            <HistoryPlugin externalHistoryState={historyState} />
          )}
          <PlainTextPlugin
            contentEditable={
              <ContentEditable
                placeholder="What's up?"
                placeholderClassName="StickyNode__placeholder"
                className="StickyNode__contentEditable"
              />
            }
            ErrorBoundary={LexicalErrorBoundary}
          />
        </LexicalNestedComposer>
      </div>
    </div>
  );
}
